class Money:
    def __init__(self, amount, currency):
        self.amount = amount
        self.currency = currency

    def __str__(self):
        return f"{self.currency} {self.amount:.2f}"

    def __repr__(self):
        return f"Money({self.amount!r}, {self.currency!r})"

wallet = Money(50, 'USD')
print(str(wallet))
print(repr(wallet))

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __eq__(self, other):
        return self.x == other.x

v1 = Vector(3, 5)
v2 = Vector(3, 5)
print(v1 == v2)

